using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithId(".NET 9").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core90))
    .AddJob(Job.Default.WithId(".NET 10").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core100));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _small = null!;
    private TextAnalyzer _large = null!;

    [GlobalSetup]
    public void Setup()
    {
        _small = new TextAnalyzer("The quick brown fox jumps over the lazy dog near the river bank");

        // ~1000 words
        var rng = new Random(42);
        var words = new string[1000];
        for (int i = 0; i < words.Length; i++)
        {
            int len = rng.Next(2, 12);
            var chars = new char[len];
            for (int j = 0; j < len; j++)
                chars[j] = (char)('a' + rng.Next(0, 26));
            words[i] = new string(chars);
        }
        _large = new TextAnalyzer(string.Join(' ', words));
    }

    [Benchmark]
    public double AverageWordLength_Small() => _small.AverageWordLength();

    [Benchmark]
    public double AverageWordLength_Large() => _large.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram_Small() => _small.WordLengthHistogram();

    [Benchmark]
    public object WordLengthHistogram_Large() => _large.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount_Small() => _small.UniqueWordCount();

    [Benchmark]
    public int UniqueWordCount_Large() => _large.UniqueWordCount();
}

